| template_name    = infobox clergy
| name             = {{#if:{{yesno|{{{child|}}}|def=}}||{{if empty|{{{subject_name|}}}|{{PAGENAMEBASE}}}}}}
| burial_place     = {{{buried|}}}
| relatives        = {{{family|}}}
