| header1          = {{#if:{{yesno|{{{child|}}}|def=}}|Ecclesiastical career}}
| label2           = Religion
|  data2           = {{{religion|}}}
| label3           = Church
|  data3           = {{if empty|{{{church|}}}|{{{Church|}}}}}
| label4           = Ordained
|  data4           = {{{ordained|}}}
| label5           = {{#if:{{{laicised|}}}|Laicised|Laicized}}
|  data5           = {{if empty|{{{laicised|}}}|{{{laicized|}}}}}
| label6           = Writings
|  data6           = {{{writings|}}}
| label7           = {{longitem|Congregations served}}
