| label8           = {{longitem|Offices held}}
|  data8           = {{{offices_held|}}}
| label9           = Title
|  data9           = {{{title|}}}
}}}}
}}<!--
-->{{#invoke:Check for clobbered parameters|check
| template = [[Template:Infobox clergy]]
| cat = {{main other|Category:Pages using infobox clergy with conflicting parameters}}
| image_name; image
